const openaiResp = $input.first().json;
const analyticsData = $('Calculate Analytics').first().json;

let reply = '';
try {
  if (openaiResp.message && openaiResp.message.content) {
    reply = openaiResp.message.content;
  } else if (openaiResp.choices && openaiResp.choices[0]) {
    reply = openaiResp.choices[0].message.content || '';
  } else if (openaiResp.text) {
    reply = openaiResp.text;
  } else {
    reply = analyticsData.summary || 'Data available but AI response failed.';
  }
} catch(e) {
  reply = analyticsData.summary || 'Error: ' + e.message;
}

return [{
  json: {
    success: true,
    reply,
    period: analyticsData.period || 'all_time',
    total_orders: analyticsData.total_orders || 0,
    total_revenue: analyticsData.total_revenue || 0,
    session_id: analyticsData.session_id || String(Date.now())
  }
}];

const classifyData = $('Classify & Build Query').first().json;
const rawInput = $input.all();

let orders = [];
for (const item of rawInput) {
  const d = item.json;
  if (Array.isArray(d)) {
    orders = orders.concat(d);
  } else if (d && (d.wc_order_id || d.id || d.status)) {
    orders.push(d);
  } else if (d && Array.isArray(d.data)) {
    orders = orders.concat(d.data);
  }
}

// ✅ If DB returned nothing at all
if (orders.length === 0) {
  const summary = `${classifyData.intentLabel}: Database mein is business ka koi bhi order record nahi mila.\nDate range checked: ${classifyData.dateFrom.split('T')[0]} to ${classifyData.dateTo.split('T')[0]}`;
  return [{ json: { ...classifyData, summary, total_orders: 0, total_revenue: 0 } }];
}

const dateFrom = new Date(classifyData.dateFrom);
const dateTo = new Date(classifyData.dateTo);

const filteredOrders = classifyData.period === 'all_time'
  ? orders
  : orders.filter(o => {
      const d = new Date(o.date_created);
      return d >= dateFrom && d <= dateTo;
    });

// ✅ NO fallback — empty period = 0 orders, honest message
const useOrders = filteredOrders;

if (useOrders.length === 0) {
  const summary = `${classifyData.intentLabel} (${classifyData.dateFrom.split('T')[0]} se ${classifyData.dateTo.split('T')[0]} tak):\n\nIs period mein koi order nahi aya.\nDatabase mein total records: ${orders.length}\nLekin requested date range mein: 0 orders`;
  return [{ json: { ...classifyData, summary, total_orders: 0, total_revenue: 0 } }];
}

let totalRevenue = 0, completedRevenue = 0, pendingRevenue = 0;
const statusCount = {}, productSales = {}, dailyRevenue = {};

for (const o of useOrders) {
  const amount = parseFloat(o.total) || 0;
  totalRevenue += amount;
  const status = (o.status || 'unknown').toLowerCase();
  statusCount[status] = (statusCount[status] || 0) + 1;
  if (['completed','processing','on-hold'].includes(status)) completedRevenue += amount;
  else if (status === 'pending') pendingRevenue += amount;

  const dateStr = (o.date_created || '').replace(' ', 'T');
  if (dateStr) {
    const day = dateStr.substring(0, 10);
    if (!dailyRevenue[day]) dailyRevenue[day] = { revenue: 0, orders: 0 };
    dailyRevenue[day].revenue += amount;
    dailyRevenue[day].orders += 1;
  }

  const lineItems = Array.isArray(o.line_items) ? o.line_items : [];
  for (const item of lineItems) {
    const name = item.name || 'Unknown';
    const qty = parseInt(item.quantity) || 1;
    const subtotal = parseFloat(item.subtotal || item.total) || 0;
    if (!productSales[name]) productSales[name] = { qty: 0, revenue: 0 };
    productSales[name].qty += qty;
    productSales[name].revenue += subtotal;
  }
}

const fmt = n => 'Rs.' + Math.round(n).toLocaleString();
const topProducts = Object.entries(productSales)
  .sort((a, b) => b[1].revenue - a[1].revenue).slice(0, 5)
  .map(([name, data]) => `• ${name}: ${fmt(data.revenue)} (${data.qty} units)`);

const statusLines = Object.entries(statusCount)
  .sort((a, b) => b[1] - a[1]).map(([s, c]) => `${s}: ${c}`);

const avgOrderValue = Math.round(totalRevenue / useOrders.length);
const sortedDays = Object.entries(dailyRevenue).sort((a, b) => b[1].revenue - a[1].revenue);
const bestDay = sortedDays[0];
const top10Days = sortedDays.slice(0, 10)
  .map(([date, data]) => `• ${date}: ${fmt(data.revenue)} (${data.orders} orders)`);

const summary = `${classifyData.intentLabel} (${classifyData.dateFrom.split('T')[0]} se ${classifyData.dateTo.split('T')[0]} tak):\n\nTotal Orders: ${useOrders.length}\nTotal Revenue: ${fmt(totalRevenue)}\nActive Revenue (completed+processing+on-hold): ${fmt(completedRevenue)}\nAverage Order Value: ${fmt(avgOrderValue)}\nOrder Status Breakdown: ${statusLines.join(', ')}\n${topProducts.length > 0 ? `\nTop Products by Revenue:\n${topProducts.join('\n')}` : ''}\n${bestDay ? `\nBest Day: ${bestDay[0]} — ${fmt(bestDay[1].revenue)} (${bestDay[1].orders} orders)` : ''}\n\nTop 10 Revenue Days:\n${top10Days.join('\n')}`;

return [{
  json: {
    ...classifyData,
    summary,
    total_orders: useOrders.length,
    total_revenue: Math.round(totalRevenue),
    analytics: { totalRevenue: Math.round(totalRevenue), completedRevenue: Math.round(completedRevenue), avgOrderValue, statusCount, topProducts, bestDay: bestDay ? bestDay[0] : null, top10Days }
  }
}];

const raw = $input.first().json;
const body = raw.body || raw;
const message = String(body.message || '').trim();
const business_id = String(body.business_id || '').trim();
const session_id = String(body.session_id || Date.now()).trim();

if (!message || !business_id) {
  return [{ json: { valid: false, error: 'message and business_id required' } }];
}

const q = message.toLowerCase();
const now = new Date();
const todayStart = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 0, 0, 0, 0);
const todayEnd = new Date(now.getFullYear(), now.getMonth(), now.getDate(), 23, 59, 59, 999);

let dateFrom, dateTo, period, intentLabel;

// ✅ Specific month+year detection — must come FIRST
const monthNames = {
  jan: 0, january: 0,
  feb: 1, february: 1,
  mar: 2, march: 2,
  apr: 3, april: 3,
  may: 4,
  jun: 5, june: 5,
  jul: 6, july: 6,
  aug: 7, august: 7,
  sep: 8, september: 8,
  oct: 9, october: 9,
  nov: 10, november: 10,
  dec: 11, december: 11
};

const monthMatch = q.match(/\b(jan(?:uary)?|feb(?:ruary)?|mar(?:ch)?|apr(?:il)?|may|jun(?:e)?|jul(?:y)?|aug(?:ust)?|sep(?:tember)?|oct(?:ober)?|nov(?:ember)?|dec(?:ember)?)\b/i);
const yearMatch = q.match(/\b(202[0-9])\b/);

if (monthMatch) {
  const monthIndex = monthNames[monthMatch[1].toLowerCase()];
  const year = yearMatch ? parseInt(yearMatch[1]) : now.getFullYear();
  period = 'specific_month';
  intentLabel = `${monthMatch[1].charAt(0).toUpperCase() + monthMatch[1].slice(1)} ${year} ki sales`;
  dateFrom = new Date(year, monthIndex, 1, 0, 0, 0, 0);
  dateTo = new Date(year, monthIndex + 1, 0, 23, 59, 59, 999);
} else if (q.includes('today') || q.includes('aaj')) {
  period = 'today'; intentLabel = 'Aaj ki sales';
  dateFrom = new Date(todayStart); dateTo = new Date(todayEnd);
} else if (q.includes('yesterday') || q.includes('kal')) {
  period = 'yesterday'; intentLabel = 'Kal ki sales';
  dateFrom = new Date(todayStart); dateFrom.setDate(dateFrom.getDate() - 1);
  dateTo = new Date(todayEnd); dateTo.setDate(dateTo.getDate() - 1);
} else if (q.includes('90 day') || q.includes('teen mahine') || q.includes('3 month')) {
  period = '90days'; intentLabel = 'Pichle 90 din ki sales';
  dateFrom = new Date(todayStart); dateFrom.setDate(dateFrom.getDate() - 90);
  dateTo = new Date(todayEnd);
} else if (q.includes('30 day') || q.includes('pichle 30')) {
  period = '30days'; intentLabel = 'Pichle 30 din ki sales';
  dateFrom = new Date(todayStart); dateFrom.setDate(dateFrom.getDate() - 30);
  dateTo = new Date(todayEnd);
} else if (q.includes('last month') || q.includes('pichle mahine')) {
  period = 'last_month'; intentLabel = 'Pichle mahine ki sales';
  dateFrom = new Date(now.getFullYear(), now.getMonth() - 1, 1, 0, 0, 0, 0);
  dateTo = new Date(now.getFullYear(), now.getMonth(), 0, 23, 59, 59, 999);
} else if (q.includes('this week') || q.includes('is hafte') || q.includes('week')) {
  period = 'week'; intentLabel = 'Is hafte ki sales';
  const d = now.getDay();
  dateFrom = new Date(todayStart); dateFrom.setDate(dateFrom.getDate() - d);
  dateTo = new Date(todayEnd);
} else if (q.includes('last week') || q.includes('pichle hafte')) {
  period = 'last_week'; intentLabel = 'Pichle hafte ki sales';
  const d = now.getDay();
  dateFrom = new Date(todayStart); dateFrom.setDate(dateFrom.getDate() - d - 7);
  dateTo = new Date(todayStart); dateTo.setDate(dateTo.getDate() - d - 1); dateTo.setHours(23,59,59,999);
} else if (q.includes('month') || q.includes('mahina') || q.includes('mahine')) {
  period = 'month'; intentLabel = 'Is mahine ki sales';
  dateFrom = new Date(now.getFullYear(), now.getMonth(), 1, 0, 0, 0, 0);
  dateTo = new Date(todayEnd);
} else if (q.includes('year') || q.includes('saal')) {
  period = 'year'; intentLabel = 'Is saal ki sales';
  dateFrom = new Date(now.getFullYear(), 0, 1, 0, 0, 0, 0);
  dateTo = new Date(todayEnd);
} else {
  period = 'all_time'; intentLabel = 'Tamam sales';
  dateFrom = new Date('2020-01-01');
  dateTo = new Date(todayEnd);
}

