const base = 'https://ibzlykqguiqbwvkbqrau.supabase.co/rest/v1/woocommerce_orders';
const fields = 'wc_order_id,order_number,status,total,customer_name,date_created,line_items';

const ordersUrl = `${base}?business_id=eq.${business_id}&select=${fields}&order=date_created.desc&limit=500`;

return [{
  json: { valid: true, message, business_id, session_id, period, intentLabel,
    dateFrom: dateFrom.toISOString(), dateTo: dateTo.toISOString(),
    ordersUrl, supaKey: SUPA_KEY, q }
}];
